43: impl CSSRule {
44:     pub(crate) fn new_inherited(parent_stylesheet: &CSSStyleSheet) -> CSSRule {
45:         CSSRule {
46:             reflector_: Reflector::new(),
47:             parent_stylesheet: Dom::from_ref(parent_stylesheet),
48:             parent_stylesheet_removed: Cell::new(false),
49:         }
50:     }
