151:     /// Sets owner sheet to null (and does the same for all children)
152:     pub(crate) fn deparent(&self) {
153:         self.parent_stylesheet_removed.set(true);
154:         // https://github.com/w3c/csswg-drafts/issues/722
155:         // Spec doesn't ask us to do this, but it makes sense
156:         // and browsers implement this behavior
157:         self.as_specific().deparent_children();
