173:                 }
174:             },
175:             StyleCssRule::Style(s) => {
176:                 if let Some(rule) = self.downcast::<CSSStyleRule>() {
177:                     rule.update_rule(s.clone(), guard);
178:                 }
179:             },
180:             StyleCssRule::FontFace(s) => {
181:                 if let Some(rule) = self.downcast::<CSSFontFaceRule>() {
182:                     rule.update_rule(s.clone());
183:                 }
184:             },
185:             StyleCssRule::FontFeatureValues(_) => unimplemented!(),
186:             StyleCssRule::CounterStyle(_) => unimplemented!(),
187:             StyleCssRule::Keyframes(s) => {
188:                 if let Some(rule) = self.downcast::<CSSKeyframesRule>() {
189:                     rule.update_rule(s.clone(), guard);
190:                 }
191:             },
192:             StyleCssRule::Media(s) => {
193:                 if let Some(rule) = self.downcast::<CSSMediaRule>() {
194:                     rule.update_rule(s.clone(), guard);
195:                 }
196:             },
197:             StyleCssRule::Namespace(s) => {
198:                 if let Some(rule) = self.downcast::<CSSNamespaceRule>() {
199:                     rule.update_rule(s.clone());
200:                 }
201:             },
202:             StyleCssRule::Supports(s) => {
203:                 if let Some(rule) = self.downcast::<CSSSupportsRule>() {
204:                     rule.update_rule(s.clone(), guard);
205:                 }
206:             },
207:             StyleCssRule::Page(_) => unreachable!(),
208:             StyleCssRule::Container(_) => unimplemented!(), // TODO
209:             StyleCssRule::Document(_) => unimplemented!(),  // TODO
210:             StyleCssRule::LayerBlock(s) => {
211:                 if let Some(rule) = self.downcast::<CSSLayerBlockRule>() {
212:                     rule.update_rule(s.clone(), guard);
213:                 }
214:             },
215:             StyleCssRule::LayerStatement(s) => {
216:                 if let Some(rule) = self.downcast::<CSSLayerStatementRule>() {
217:                     rule.update_rule(s.clone());
218:                 }
219:             },
220:             StyleCssRule::FontPaletteValues(_) => unimplemented!(), // TODO
221:             StyleCssRule::Property(s) => {
222:                 if let Some(rule) = self.downcast::<CSSPropertyRule>() {
223:                     rule.update_rule(s.clone());
224:                 }
225:             },
226:             StyleCssRule::Margin(_) => unimplemented!(), // TODO
227:             StyleCssRule::Scope(_) => unimplemented!(),  // TODO
228:             StyleCssRule::StartingStyle(_) => unimplemented!(), // TODO
229:             StyleCssRule::PositionTry(_) => unimplemented!(), // TODO
230:             StyleCssRule::CustomMedia(_) => unimplemented!(), // TODO
231:             StyleCssRule::NestedDeclarations(s) => {
