240: impl CSSRuleMethods<crate::DomTypeHolder> for CSSRule {
241:     /// <https://drafts.csswg.org/cssom/#dom-cssrule-type>
242:     fn Type(&self) -> u16 {
243:         let rule_type = self.as_specific().ty() as u16;
